def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        cumulative_sum = 0
        for n in range(1, 20):
            if n % 5 == 0:
                multiplier = 1.5
            elif n % 4 == 0:
                multiplier = 1.3
            elif n % 3 == 0:
                multiplier = 1.2
            elif n % 2 == 0:
                multiplier = 1.1
            else:
                multiplier = 0.9
            term = multiplier * ((ratio ** n) / (n**3))
            cumulative_sum += term
            if cumulative_sum > 2.5:
                cumulative_sum *= 0.85
            if 0.4 < ratio < 0.6 and n > 5:
                cumulative_sum += 0.05 * n / ratio
        score = cumulative_sum
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3
        elif remaining < 0.05 * capacity:
            score *= 1.8
        elif remaining < 0.15 * capacity:
            score *= 1.3
        elif remaining < 0.3 * capacity:
            score *= 0.9
        else:
            score *= 0.6
        mod_factors = {3: 0.07, 5: 0.12, 7: 0.15, 11: 0.18}
        mod_count = sum(1 for key in mod_factors if int(capacity) % key == 0)
        mod_score = 0
        for key, val in mod_factors.items():
            if int(capacity) % key == 0:
                mod_score += val * (capacity / (key*5))
        if mod_count >= 3:
            score -= mod_score * 1.3
        elif mod_count == 2:
            score -= mod_score * 1.1
        elif mod_count == 1:
            score -= mod_score * 0.8
        else:
            score -= (capacity / 40) * 0.05
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.02 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k * (1 + (k/10))
            elif diff < 3 * threshold:
                penalty += 0.12 * k
            else:
                penalty -= 0.07 * k
            if k % 2 == 0 and diff < threshold:
                penalty *= 1.05
        score += penalty
        if score < 0:
            score = 0
        if score > 2:
            for m in range(1, 5):
                val = capacity / m
                if abs(val - item) < 0.015 * val:
                    score *= (1 + 0.07 * m)
                elif abs(val - 2*item) < 0.02 * val:
                    score *= (1 + 0.05 * m)
        adjustment_factor = np.log1p(capacity) / 15
        if ratio > 0.8:
            score *= (1 + adjustment_factor * 1.2)
        elif ratio > 0.5:
            score *= (1 + adjustment_factor * 0.8)
        else:
            score *= (1 + adjustment_factor * 0.5)
        if int(capacity) % 13 == 0:
            score *= 0.9
        elif int(capacity) % 17 == 0:
            score *= 0.85
        if score > 5:
            score = 5 + np.tanh(score - 5)
        priorities[i] = score
    return priorities
